      throw new Error('Invalid email or password');
    }

    return {
      id: 'user-001',
      name: 'Oliver Queen',
      email: MOCK_EMAIL,
      avatarInitials: 'OQ',
      provider: 'email',
    };
  }

  async loginWithGoogle(): Promise<User> {
