import { Component } from '@angular/core';
import { RouterOutlet } from '@angular/router';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [RouterOutlet],
  template: `<router-outlet/>`,
})
export class AppComponent {}

import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-avatar',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div
      [class]="sizeClass"
      class="rounded-full bg-blue-600/25 flex items-center justify-center
             flex-shrink-0 font-semibold text-blue-300 select-none"
    >
      {{ initials }}
    </div>
  `,
})
export class AvatarComponent {
  @Input({ required: true }) initials!: string;
  @Input() size: 'sm' | 'md' | 'lg' = 'md';

  get sizeClass(): string {
    const map: Record<string, string> = {
      sm: 'w-8 h-8 text-xs',
      md: 'w-10 h-10 text-sm',
      lg: 'w-12 h-12 text-base',
    };
    return map[this.size];
  }
}

import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Comment } from '../../../core/models/post.model';
import { AvatarComponent } from '../../../shared/components/avatar.component';
import { formatRelativeTime } from '../../../shared/utils/helpers';

@Component({
  selector: 'app-comment',
  standalone: true,
  imports: [CommonModule, AvatarComponent],
  template: `
    <div class="flex gap-2.5">
      <app-avatar [initials]="comment.author.initials" size="sm"/>
      <div class="flex-1 min-w-0">
        <div class="bg-white/5 rounded-xl px-3 py-2">
          <span class="text-sm font-semibold text-white">
            {{ comment.author.name }}
          </span>
          <p class="text-sm text-slate-300 mt-0.5 leading-relaxed break-words">
            {{ comment.content }}
          </p>
        </div>
        <p class="text-xs text-slate-500 mt-1 ml-3">
          {{ relativeTime }}
        </p>
      </div>
    </div>
  `,
})
export class CommentComponent {
  @Input({ required: true }) comment!: Comment;

  get relativeTime(): string {
    return formatRelativeTime(this.comment.createdAt);
  }
}

import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormControl } from '@angular/forms';

@Component({
  selector: 'app-form-field',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  template: `
    <div>
      <!-- Label -->
      <label class="block text-sm font-medium text-slate-300 mb-1.5">
        {{ label }}
      </label>

      <!-- Input wrapper -->
      <div class="relative">
        <input
          [type]="isPassword ? (showPassword ? 'text' : 'password') : type"
          [placeholder]="placeholder"
          [formControl]="control"
          class="w-full bg-white/5 border text-white placeholder-slate-500
                 rounded-xl px-4 py-2.5 text-sm outline-none transition-colors pr-10"
          [ngClass]="{
            'border-white/10': !invalid,
            'focus:border-blue-500': !invalid,
            'border-red-500': invalid,
          }"
        />

        <!-- 👁 Toggle password -->
        <button
          *ngIf="isPassword"
          type="button"
          (click)="togglePassword()"
          class="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"
        >
          {{ showPassword ? '🙈' : '👁' }}
        </button>
      </div>

      <!-- Error -->
      <p *ngIf="invalid" class="text-red-400 text-xs mt-1">
        {{ error }}
      </p>
    </div>
  `,
})
export class FormFieldComponent {
  @Input() label: string = '';
  @Input() type: string = 'text';
  @Input() placeholder: string = '';
  @Input({ required: true }) control!: FormControl;
  @Input() error: string = '';

  showPassword = false;

  get invalid(): boolean {
    return this.control?.invalid && this.control?.touched;
  }

  get isPassword(): boolean {
    return this.type === 'password';
  }

  togglePassword(): void {
    this.showPassword = !this.showPassword;
  }
}

