signalStore(
  { providedIn: 'root' },

  withState<AuthState>(initialState),

  withComputed((store) => ({
    currentUser: computed(() => store.user()),
    isLoggedIn: computed(() => store.isAuthenticated()),
    isHydrated: computed(() => store.isHydrated()),
    displayName: computed(() => store.user()?.name ?? ''),
    userInitials: computed(() => store.user()?.avatarInitials ?? ''),
  })),

  withMethods((store) => {
    const storage = inject(StorageService);
    const router = inject(Router);
    const authService = inject(AuthService);

    return {
      hydrate(): void {
        const user = storage.get<User>(AUTH_KEY);

        if (user) {
          patchState(store, {
            user,
            isAuthenticated: true,
            isHydrated: true,
          });
        } else {
          patchState(store, {
            isHydrated: true,
          });
        }
      },
      async login(credentials: AuthCredentials): Promise<void> {
        patchState(store, { isLoading: true, error: null });
        try {
          const user = await authService.loginWithEmail(credentials);
          storage.set<User>(AUTH_KEY, user);
          patchState(store, { user, isAuthenticated: true, isLoading: false });
          await router.navigate(['/feed']);
        } catch (err) {
          const message = err instanceof Error ? err.message : 'Login failed';
          patchState(store, { isLoading: false, error: message });
        }
      },

      async loginWithGoogle(): Promise<void> {
        patchState(store, { isLoading: true, error: null });
        try {
          const user = await authService.loginWithGoogle();
          storage.set<User>(AUTH_KEY, user);
          patchState(store, { user, isAuthenticated: true, isLoading: false });
          await router.navigate(['/feed']);
        } catch (err) {
          const message =
            err instanceof Error ? err.message : 'Google login failed';
          patchState(store, { isLoading: false, error: message });
        }
      },

      logout(): void {
        storage.remove(AUTH_KEY);
        patchState(store, {
          user: null,
          isAuthenticated: false,
          error: null,
          isLoading: false,
        });
        router.navigate(['/login']);
      },

      clearError(): void {
        patchState(store, { error: null });
      },
    };
  }),
)

async () => {
  const feedStore = inject(FeedStore);

  await feedStore.loadPosts();

  return true;
}

signalStore(
  { providedIn: 'root' },

  withState<FeedState>(initialState),

  withComputed((store) => ({
    sortedPosts: computed(() =>
      [...store.posts()].sort(
        (a, b) =>
          new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
      ),
    ),
    postCount: computed(() => store.posts().length),
  })),

  withMethods((store) => {
    const feedService = inject(FeedService);
    const storageService = inject(StorageService);
    const authStore = inject(AuthStore);

    function persist(posts: Post[]): void {
      storageService.set<Post[]>(FEED_KEY, posts);
      patchState(store, { posts });
    }

    return {
      hydrate(): void {
        const posts = storageService.get<Post[]>(FEED_KEY) ?? [];
        patchState(store, { posts });
      },

      async loadPosts(): Promise<void> {
        if (store.posts().length > 0) return;

        patchState(store, { isLoading: true, error: null });
        try {
          const posts = await feedService.getMockPosts();
          persist(posts);
          patchState(store, { isLoading: false });
        } catch (err) {
          const message =
            err instanceof Error ? err.message : 'Failed to load posts';
          patchState(store, { isLoading: false, error: message });
        }
      },

      createPost(payload: CreatePostPayload): void {
        const user = authStore.currentUser();
        if (!user) return;

        const newPost: Post = {
          id: generateId(),
          author: {
            id: user.id,
            name: user.name,
            initials: user.avatarInitials,
          },
          content: payload.content,
          imageUrl: payload.imageUrl,
          likes: [],
          comments: [],
          createdAt: nowISO(),
        };

        persist([newPost, ...store.posts()]);
      },

      addComment(payload: CreateCommentPayload): void {
        const user = authStore.currentUser();
        if (!user) return;

        const comment: Comment = {
          id: generateId(),
          postId: payload.postId,
          author: {
            id: user.id,
            name: user.name,
            initials: user.avatarInitials,
          },
          content: payload.content,
          createdAt: nowISO(),
        };

        const updated = store
          .posts()
          .map(
            (post): Post =>
              post.id === payload.postId
                ? { ...post, comments: [...post.comments, comment] }
                : post,
          );

        persist(updated);
      },

      toggleLike(postId: string): void {
        const userId = authStore.currentUser()?.id;
        if (!userId) return;

        const updated = store.posts().map((post): Post => {
          if (post.id !== postId) return post;

          const alreadyLiked = post.likes.includes(userId);

          return {
            ...post,
            likes: alreadyLiked
              ? post.likes.filter((id) => id !== userId)
              : [...post.likes, userId],
          };
        });

        persist(updated);
      },
    };
  }),
)

() => {
